import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / processing fee ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Single main items at base price ---
  it("single plain sword for a newcomer (first insurance) → premium 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });

  // --- Components and blocks ---
  it("2 runes for a newcomer → 60 G premium (50 base + 5 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes for a newcomer → 71 G premium (60 block + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (3+3+1: only one block applies — actually 7=3+4 → one block? spec says 175)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword adds 50% surcharge on the cursed item's base premium");
  it.todo("highly enchanted item (enchantment >= 5) adds 30% surcharge on that item's base");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // --- Modifier scope on multi-item policies ---
  it.todo("policy with cursed sword + plain amulet → cursed surcharge applies only to cursed item's base (210 G before further modifiers and fee)");

  // --- Policy-wide modifiers and thresholds ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance carries a 10% initial assessment surcharge (policy-wide)");
  it.todo("follow-up contract: 15% discount on each contract after the first");

  // --- Rounding ---
  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7) → premium 160 G");

  // --- Errors on quote ---
  it.todo("quote includes unknown item type → CLI exits non-zero, error on stderr, no results on stdout");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both clauses apply; 50% wins)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause applies)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause applies)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies once per damaged item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("two-sword policy: dragon attack damages both swords → each damage entry gets its own deductible");
  it.todo("more damages of a type than insured → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword cap is based on unmodified insurance value (cap 2000 G), not modified premium");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("two successive 1500 G claims on sword policy (cap 2000): first payout 1400 G remainingCap 600 G; second payout 600 G remainingCap 0 G");

  // --- Claim errors ---
  it.todo("claim references damage to item not part of policy → CLI exits non-zero");
  it.todo("claim references damage with unknown item type → CLI exits non-zero");
  it.todo("claim contains a damage with amount -200 → CLI exits non-zero");
});

