export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Step = {
  op: string;
  items?: Item[];
};

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type ScenarioResult = {
  results: unknown[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const groupCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  return counts;
};

const basePremiumForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
  return count * ITEM_BASE_PREMIUM[type];
};

const sumBasePremium = (counts: Map<string, number>): number => {
  let total = 0;
  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
  return total;
};

const calculatePremium = (items: Item[]): number => {
  const base = sumBasePremium(groupCountsByType(items));
  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({
    premium: calculatePremium(step.items ?? []),
  }));
  return { results };
};

