import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / processing fee ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Single main items at base price ---
  it("single plain sword for a newcomer (first insurance) → premium 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });

  // --- Components and blocks ---
  it("2 runes for a newcomer → 60 G premium (50 base + 5 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes for a newcomer → 71 G premium (60 block + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (3+3+1: only one block applies — actually 7=3+4 → one block? spec says 175)");
  it("2 runes + 1 moonstone for a newcomer → 88 G premium (75 base + 7.5 first-insurance + 5 fee, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Item-specific modifiers ---
  it("newcomer with cursed sword (steel, enchantment 3) → premium 165 G (integration example: 100 base + 50 curse + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("newcomer with sword (steel, enchantment 5, not cursed) → premium 145 G (100 base + 30 high-enchantment + 10 first-insurance + 5 fee; threshold inclusive)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // --- Modifier scope on multi-item policies ---
  it.todo("policy with cursed sword + plain amulet → cursed surcharge applies only to cursed item's base (210 G before further modifiers and fee)");

  // --- Policy-wide modifiers and thresholds ---
  it("customer with exactly 2 years, plain sword → premium 95 G (100 base − 20 loyalty + 10 first-insurance + 5 fee; threshold inclusive)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it.todo("first insurance carries a 10% initial assessment surcharge (policy-wide)");
  it.todo("follow-up contract: 15% discount on each contract after the first");

  // --- Rounding ---
  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");

  // --- Integration examples ---
  it("long-standing customer's second contract: cursed sword (steel, enchantment 7) → premium 160 G (integration example: 100 + 50 + 30 − 20 + 10 − 15 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }],
        },
      ],
    });
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // --- Errors on quote ---
  it.todo("quote includes unknown item type → CLI exits non-zero, error on stderr, no results on stdout");

  // --- Claim: standard reimbursement ---
  it("regular sword damage 500 G → payout 400 G, remainingCap 1600 G (full reimbursement minus 100 deductible; cap = 2×1000)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });
  it("rune damage 200 G → payout 100 G, remainingCap 400 G (insurance 250; cap 500)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "theft", damages: [{ itemType: "rune", amount: 200 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 100, remainingCap: 400 });
  });

  // --- Claim: enchantment threshold ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both clauses apply; 50% wins)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause applies)");
  it("steel sword enchantment 9, damage 1000 G → payout 400 G, remainingCap 1600 G (50% high-enchantment then deductible)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 9, cursed: false }],
        },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1000 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies once per damaged item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("two-sword policy: dragon attack damages both swords → each damage entry gets its own deductible");
  it.todo("more damages of a type than insured → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword cap is based on unmodified insurance value (cap 2000 G), not modified premium");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("two successive 1500 G claims on sword policy (cap 2000): first payout 1400 G remainingCap 600 G; second payout 600 G remainingCap 0 G");

  // --- Claim errors ---
  it.todo("claim references damage to item not part of policy → CLI exits non-zero");
  it.todo("claim references damage with unknown item type → CLI exits non-zero");
  it.todo("claim contains a damage with amount -200 → CLI exits non-zero");
});

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
export type Step = QuoteStep | ClaimStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const DEDUCTIBLE_PER_DAMAGE = 100;
const CAP_MULTIPLIER = 2;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  rune: 25,
  moonstone: 25,
};

const ITEM_INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  rune: 250,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const groupCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  return counts;
};

const basePremiumForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
  return count * ITEM_BASE_PREMIUM[type];
};

const sumBasePremium = (counts: Map<string, number>): number => {
  let total = 0;
  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
  return total;
};

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRateForItem = (item: Item): number =>
  (item.cursed ? CURSED_SURCHARGE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);

const surchargeForItem = (item: Item): number =>
  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);

const itemSurcharges = (items: Item[]): number =>
  items.reduce((total, item) => total + surchargeForItem(item), 0);

const calculatePremium = (
  items: Item[],
  yearsWithMHPCO: number,
  isFollowUpContract: boolean,
): number => {
  const base = sumBasePremium(groupCountsByType(items));
  const surcharges = itemSurcharges(items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
  const loyaltyDiscount =
    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
  return Math.ceil(
    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
  );
};

type Policy = {
  items: Item[];
  remainingCap: number;
};

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const claimPayout = (policy: Policy, incident: Incident): number => {
  const grossPayout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
  return Math.floor(Math.min(grossPayout, policy.remainingCap));
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Policy[] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUpContract = policies.length >= 1;
      policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
      return {
        premium: calculatePremium(step.items, scenario.customer.yearsWithMHPCO, isFollowUpContract),
      };
    }
    const policy = policies[step.policy];
    const payout = claimPayout(policy, step.incident);
    policy.remainingCap -= payout;
    return { payout, remainingCap: policy.remainingCap };
  });
  return { results };
};

