import { readFileSync } from "node:fs";
import { runScenario, type Scenario } from "./claim-office.js";

const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);

const findUnknownItemTypeInQuote = (scenario: Scenario): string | undefined => {
  for (const step of scenario.steps) {
    if (step.op !== "quote") continue;
    for (const item of step.items) {
      if (!KNOWN_ITEM_TYPES.has(item.type)) return item.type;
    }
  }
  return undefined;
};

const findClaimAgainstUninsuredItem = (scenario: Scenario): string | undefined => {
  const insuredTypes: Set<string>[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      insuredTypes.push(new Set(step.items.map((item) => item.type)));
      continue;
    }
    const policyTypes = insuredTypes[step.policy];
    for (const damage of step.incident.damages) {
      if (!policyTypes?.has(damage.itemType)) return damage.itemType;
    }
  }
  return undefined;
};

const die = (message: string): never => {
  process.stderr.write(`${message}\n`);
  process.exit(1);
};

const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));

const unknownType = findUnknownItemTypeInQuote(scenario);
if (unknownType !== undefined) die(`Unknown item type: ${unknownType}`);

const uninsuredItemType = findClaimAgainstUninsuredItem(scenario);
if (uninsuredItemType !== undefined) die(`Claim references item not in policy: ${uninsuredItemType}`);

process.stdout.write(JSON.stringify(runScenario(scenario)));

